async function main() {
  let updated = 0, failed = 0;
  for (const item of updates) {
    try {
      const result = await prisma.product.update({ where:{slug:item.slug}, data:{description:item.description, metaDescription:item.metaDescription} });
      console.log(`✅ Updated: ${result.title}`);
      updated++;
    } catch (err) { console.log(`❌ Failed: ${item.slug} — ${err.message}`); failed++; }
  }
  console.log(`\nBatch R4E-F-G complete: ${updated} updated, ${failed} failed`);
}
main().then(() => prisma.$disconnect());
